ps.pstext:
if !IsFeatureImplemented(FEAT_SVE) || !IsFeatureImplemented(FEAT_CPA) then
    EndOfDecode(Decode_UNDEF);
end;
let dn : integer = UInt(Zdn);
let m : integer  = UInt(Zm);
let a : integer  = UInt(Za);

CheckNonStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV 64;
let operand1 : bits(VL) = Z{}(dn);
let operand2 : bits(VL) = Z{}(m);
let operand3 : bits(VL) = Z{}(a);
var result : bits(VL);

for e = 0 to elements-1 do
    let element1 : integer = SInt(operand1[e*:64]);
    let element2 : integer = SInt(operand2[e*:64]);
    let product : integer = element1 * element2;
    let overflow : boolean = (product != SInt(product[63:0]));
    let addend : bits(64) = operand3[e*:64];
    result[e*:64] = PointerMultiplyAddCheck(addend + product, addend, overflow);
end;

Z{VL}(dn) = result;
